function mapOpenAIBatchStatus(s: string): BatchStatus {
  switch (s) {
    case 'completed': return 'completed';
    case 'failed': return 'failed';
    case 'expired': return 'expired';
    case 'cancelling':
    case 'cancelled':
      return 'canceled';
    case 'validating':
    case 'in_progress':
    case 'finalizing':
      return 'in_progress';
    default:
      // Unknown → treat as still-running so the drain task polls again
      return 'in_progress';
  }
}

