    const bucketName = process.env.GOOGLE_VERTEX_BATCH_GCS_BUCKET;
    if (!bucketName) {
      throw new Error(
        'VertexGeminiAdapter.submitBatch: GOOGLE_VERTEX_BATCH_GCS_BUCKET is not set. ' +
