    const outputGcsPrefix = `gs://${bucketName}/${outputObjectPrefix}`;

    const batch = await this.client.batches.create({
      model: route.modelId,
      src: { format: 'jsonl', gcsUri: [inputGcsUri] },
      config: {
        dest: { format: 'jsonl', gcsUri: outputGcsPrefix },
        displayName: folderId,
