/**
 * Translate a chat message's `content` into Vertex `parts`.
 *
 * - A plain string becomes a single text part.
 * - An array may interleave text parts and inline image parts:
 *     { type: 'text', text }                       -> { text }
 *     { type: 'image'|'file', mimeType, data: <base64> } -> { inlineData: { mimeType, data } }
 *   Inline base64 images are how the document-ingestion worker feeds an
 *   uploaded image to Gemini for its vision-transcription pass (a lone image is
 *   far below the explicit-cache token minimum, so the fileData/cache path
 *   isn't viable for it).
 * - Any other shape is stringified into a text part so content is never
 *   silently dropped.
 */
function toVertexParts(content: unknown): Part[] {
  if (typeof content === 'string') return [{ text: content }];
  if (!Array.isArray(content)) return [{ text: String(content ?? '') }];
  const parts: Part[] = [];
  for (const raw of content) {
    if (raw && typeof raw === 'object') {
      const part = raw as Record<string, unknown>;
      if (
        (part.type === 'image' || part.type === 'file') &&
        typeof part.data === 'string' &&
        typeof part.mimeType === 'string'
      ) {
        // Gemini ingests both images and documents (e.g. application/pdf) via
        // inlineData with the source mime type.
        parts.push({ inlineData: { mimeType: part.mimeType, data: part.data } });
        continue;
      }
      if ((part.type === 'text' || part.type === undefined) && typeof part.text === 'string') {
        parts.push({ text: part.text });
        continue;
      }
    }
    parts.push({ text: String(raw) });
  }
  return parts;
}

/**
 * Flatten the OraclePromptPlan into a (systemPrompt, userMessage) pair.
 * Stable blocks become the system prompt; semi-stable / retrieved / dynamic
 * blocks concatenate into the user message in order. Preserves cacheable-
 * prefix ordering so provider-native cache machinery actually hits.
 */
export function flattenPlan(plan: OraclePromptPlan): {
  systemPrompt: string;
  userMessage: string;
} {
  const { systemPrompt, prefixContext, dynamicInput } = splitPlanForCaching(plan);
  return {
    systemPrompt,
    userMessage: [prefixContext, dynamicInput].filter(Boolean).join('\n\n'),
  };
