 */
function vertexThinkingConfig(effort: ReasoningEffort | undefined):
  | { thinkingConfig: { thinkingBudget: number } }
  | Record<string, never> {
  if (!effort) return {};
  const budget =
    effort === 'off' ? 0
      : effort === 'low' ? 1024
      : effort === 'medium' ? 8192
      : 24576;
  return { thinkingConfig: { thinkingBudget: budget } };
