      outputTokens: u?.output_tokens,
      cachedInputTokens: u?.input_tokens_details?.cached_tokens,
      reasoningTokens: u?.output_tokens_details?.reasoning_tokens,
      latencyMs,
      providerRequestId: response.id,
      rawUsageJson: u,
