}

export function missingRequirements(
  model: Pick<
    ModelCapability,
    | 'provider'
    | 'vision'
    | 'thinking'
    | 'structuredOutputs'
    | 'toolCalling'
    | 'outputCap'
    | 'pdf'
    | 'promptCaching'
    | 'contextLength'
  >,
  slot: ModelSlot,
): string[] {
  const missing: string[] = [];
  for (const req of requiredCapabilitiesFor(slot)) {
    if (req.kind === 'capability') {
      if (!model[req.field]) missing.push(req.label);
    } else if (model.contextLength == null || model.contextLength <= req.minExclusive) {
      missing.push(req.label);
    }
  }
  if (
    (slot === 'workflow_read' || slot === 'macro' || slot === 'model_merge') &&
    (model.provider === 'google' || model.provider === 'qwen' || model.provider === 'deepseek')
  ) {
    missing.push(
      model.provider === 'google'
        ? 'complex structured outputs (Gemini schema complexity limit)'
        : 'strict JSON Schema enforcement',
    );
  }
  return missing;
