                      No models match &ldquo;{query}&rdquo;
                    </li>
                  )}
                  {filtered.map((m) => {
                    const badge = priceBadge(m);
                    const isSelected = m.id === selected;
                    return (
                      <li key={m.id} role="option" aria-selected={isSelected}>
                        <button
