    .replace(/-\d{8}$/, '')
    .replace(/-\d{4}$/, '');
  if (stripped !== modelId) {
    const v = tryKey(stripped);
    if (v) return { enrichment: v, matched: true };
  }

  // 3. Dash → dot for version numbers (after stripping)
  const dotted = stripped.replace(/-(\d)-(\d)(?=-|$)/g, '-$1.$2');
